    {&#x27;target&#x27;: &#x27;math.add&#x27;, &#x27;args&#x27;: [1, 2]},
    {&#x27;target&#x27;: &#x27;math.multiply&#x27;, &#x27;args&#x27;: [3, 4]},
])

